/*此处是顺序栈数据结构定义*/
typedef int DataType;
struct seqStack
{//有3个数据成员
  int MAXNUM;//用于记录顺序栈中能存放的最大元素个数的 整型 MAXNUM
  int top;//用于存放顺序栈的栈顶位置，初始化为0或-1 均可  整型  curNum
  DataType *element;//用于存放顺序栈数据元素的连续空间的起始地址
};

typedef struct seqStack *PseqStack;
//第一关
PseqStack createNullStack_seq(int m)
{ //此处填写代码，创建一个空的顺序栈，能存放的最大元素个数为 m
  //若m=0，则返回NULL
  if (m <= 0) {
    return NULL;
  }
  PseqStack stack = (PseqStack)malloc(sizeof(struct seqStack));
  if (stack == NULL) {
    return NULL;
  }
  stack->element = (DataType *)malloc(m * sizeof(DataType));
  if (stack->element == NULL) {
    free(stack);
