#include <stdio.h>
#include <stdlib.h>

/*此处是顺序栈数据结构定义*/
typedef int DataType;
struct seqStack
{//有3个数据成员
  int MAXNUM;//用于记录顺序栈中能存放的最大元素个数的 整型 MAXNUM
  int top;//用于存放顺序栈的栈顶位置，初始化为0或-1 均可  整型  curNum
  DataType *element;//用于存放顺序栈数据元素的连续空间的起始地址
};

typedef struct seqStack *PseqStack;
//第一关
PseqStack createNullStack_seq(int m)
{//此处填写代码，创建一个空的顺序栈，能存放的最大元素个数为 m,栈顶top设置为0
 //若m=0，则返回NULL
    if (m <= 0) {
        return NULL;
    }

    PseqStack stack = (PseqStack)malloc(sizeof(struct seqStack));
    if (stack == NULL) {
        return NULL;
    }

    stack->element = (DataType*)malloc(sizeof(DataType) * m);
    if (stack->element == NULL) {
        free(stack);
        return NULL;
    }

    stack->MAXNUM = m;
    stack->top = 0;  // 栈顶指针初始化为0，表示空栈

    return stack;
}

//第二关
int isNullStack_seq(PseqStack L)
{
  //判断顺序栈是否为空，若为空，返回值为1，否则返回值为0,若栈不存在，则返回-1
    if (L == NULL) {
        return -1;
    }
    return L->top == 0 ? 1 : 0;
}

//第三关
int isFullStack_seq(PseqStack L)
{
  //判断顺序栈是否已满，若已满，返回值为1，否则返回值为0
    if (L == NULL) {
        return -1;
    }
    return L->top == L->MAXNUM ? 1 : 0;
}

//第四关
int push_seq(PseqStack L ,DataType x)
{//在顺序栈中插入数据元素x，若插入不成功，返回0；插入成功返回值为1
    if (L == NULL || L->top == L->MAXNUM) {
        return 0;
    }
    L->element[L->top] = x;
    L->top++;
    return 1;
}

//第五关
DataType pop_seq(PseqStack L)
{//弹栈并返回删除元素，若栈为空，则返回-1
    if (L == NULL || L->top == 0) {
        return -1;
    }
    L->top--;
    return L->element[L->top];
}

//第六关
DataType top_seq(PseqStack L)
{// 取栈顶元素返回，若栈为空，则返回-1
    if (L == NULL || L->top == 0) {
        return -1;
    }
    return L->element[L->top - 1];
}

//销毁顺序栈，释放栈所占存储空间
int destroystack_seq(PseqStack L)
{
    //返回值为销毁的栈中现有数据元素的个数，若待销毁的线性表不存在，则返回0
    if (L == NULL) {
        return 0;
    }
    int count = L->top;
    free(L->element);
    free(L);
    return count;
}

//第七关
//使用已实现的栈操作，实现数制转换

void print(PseqStack L)
{
//逐个弹出栈L中的数据元素并输出，输出数据间不需要任何间隔符号
    while (L->top > 0) {
        DataType value = pop_seq(L);
        if (value >= 10) {
            printf("%c", 'A' + (value - 10));
        } else {
            printf("%d", value);
        }
    }
}

void convert(int data , int k)
{
//利用栈实现将data转换为k进制，k可能是2，8，16. 在本函数内实现转换并调用print函数输出转换后的结果
//十六进制时输出 A ,B ,C, D,E,F 使用大写字母
    if (k != 2 && k != 8 && k != 16) {
        return;
    }

    PseqStack stack = createNullStack_seq(32); // 假设最大32位
    if (stack == NULL) {
        return;
    }

    int temp = data;
    if (temp == 0) {
        push_seq(stack, 0);
    } else {
        while (temp > 0) {
            int remainder = temp % k;
            push_seq(stack, remainder);
            temp = temp / k;
        }
    }

    print(stack);
    destroystack_seq(stack);
}
